function daysToSeconds(days) {
  return days * 86400;
}

function secondsToDays(seconds) {
  return seconds / 86400;
}

function isMoreThanOneDay(seconds) {
  return seconds > 86400;
}

module.exports = { daysToSeconds, secondsToDays, isMoreThanOneDay };

